#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""THE FIX (exit-0-safe): disable the recurring-DDL timers (icp-rank/icp-sweep/geo) whose
ALTER TABLE ADD COLUMN re-runs perpetually gridlock atlas.business. Columns already exist
so these re-runs are pure harm. Kill current ALTERs, then measure that enrichment finally
flows (done-count delta, re-enrich still paused so it's the true rate)."""
import os,sys,json,time,subprocess
def sh(c,t=25):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else None)
out={"kind":"killtimers","ts":int(time.time())}
try:
    units=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}'").split()
    # any timer that runs a DDL-issuing job: icp rank/sweep, geo
    tgt=[u for u in units if u.endswith('.timer') and any(k in u.lower() for k in ['icp','sweep','geo','rank'])]
    out["timers_targeted"]=tgt
    done=[]
    for u in tgt:
        done.append(u+":"+sh("systemctl stop %s 2>&1; systemctl disable %s 2>&1 | tail -1; echo ok"%(u,u)))
    out["disabled"]=done
    # also disable the matching .service so a manual/queued trigger can't re-fire DDL
    for u in [t.replace('.timer','.service') for t in tgt]:
        sh("systemctl stop %s 2>/dev/null"%u)
    # kill any ALTER TABLE active now
    out["killed_alter"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE query ILIKE 'ALTER TABLE%' AND state='active') x")
    out["killed_blockers"]=psql("""SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM (SELECT DISTINCT bl.pid FROM pg_stat_activity w JOIN LATERAL unnest(pg_blocking_pids(w.pid)) AS bl(pid) ON true JOIN pg_stat_activity a ON a.pid=bl.pid WHERE now()-a.state_change>interval '20 seconds') z) y""")
    time.sleep(8)
    # NOW measure true enrichment over 40s (gridlock gone, re-enrich paused)
    d0=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t0=time.time()
    time.sleep(40)
    d1=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t1=time.time()
    out["done_t0"]=d0; out["done_t1"]=d1
    try: out["TRUE_enrich_per_min"]=round((int(d1)-int(d0))*60.0/(t1-t0),1)
    except Exception: pass
    out["active_after"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["total_after"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["waiting_lock_after"]=psql("SELECT count(*) FROM pg_stat_activity WHERE wait_event_type='Lock'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/killtimers.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"killtimers","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
